export declare const code = "/* Each particle gets an individual offset-path pointing in its own direction.\n   The burst effect is just staggered delays + the same @keyframes. */\n\n// Generate N rays evenly around a circle\nconst rays = Array.from({ length: 8 }, (_, i) => {\n  const angle = (i / 8) * 360;\n  const rad   = angle * Math.PI / 180;\n  const dx    = Math.cos(rad) * 80;\n  const dy    = Math.sin(rad) * 80;\n  return {\n    path: `path('M 0 0 L ${dx} ${dy}')`,\n    delay: i * 0.18\n  };\n});\n\n// Apply per-element:\n<div style={{\n  offsetPath: ray.path,\n  animationDelay: ray.delay + 's',\n  color: `oklch(68% .25 ${angle})`\n}} />";
export default function H3RayBurst(): import("react/jsx-runtime").JSX.Element;
